const cases = [
  { name: 'array of strings', data: ['A55001213ZX0A'], expected: 'pass' },
  { name: 'array of numbers', data: [1, 2, 3], expected: 'pass' },
  { name: 'plain object', data: { id: 1 }, expected: 'pass' },
  { name: 'non-json text', data: 'hello', expected: 'fail' },
  { name: 'null body', data: null, expected: 'fail' }
];

